loop {
    let (stream, _) = listener.accept().await?;
    let io = TokioIo::new(stream);

    // Each connection could send multiple requests, so
    // the `Service` needs a clone to handle later requests.
    let counter = counter.clone();

    // This is the `Service` that will handle the connection.
    // `service_fn` is a helper to convert a function that
    // returns a Response into a `Service`.
    let service = service_fn(move |_req| {
        // Get the current count, and also increment by 1, in a single
        // atomic operation.
        let count = counter.fetch_add(1, Ordering::AcqRel);
        async move {
            Ok::<_, Error>(Response::new(Full::new(Bytes::from(format!(
                "Request #{}",
                count
            )))))
        }
    });

    if let Err(err) = http1::Builder::new().serve_connection(io, service).await {
        println!("Error serving connection: {:?}", err);
    }
}

impl Service<Request<IncomingBody>> for Svc {
    type Response = Response<Full<Bytes>>;
    type Error = hyper::Error;
    type Future = Pin<Box<dyn Future<Output = Result<Self::Response, Self::Error>> + Send>>;

    fn call(&self, req: Request<IncomingBody>) -> Self::Future {
        fn mk_response(s: String) -> Result<Response<Full<Bytes>>, hyper::Error> {
            Ok(Response::new(Full::new(Bytes::from(s))))
        }

        if req.uri().path() != "/favicon.ico" {
            *self.counter.lock().expect("lock poisoned") += 1;
        }

        let res = match req.uri().path() {
            "/" => mk_response(format!("home! counter = {:?}", self.counter)),
            "/posts" => mk_response(format!("posts, of course! counter = {:?}", self.counter)),
            "/authors" => mk_response(format!(
                "authors extraordinare! counter = {:?}",
                self.counter
            )),
            _ => mk_response("oh no! not found".into()),
        };

        Box::pin(async { res })
    }
}

loop {
    let (stream, _) = listener.accept().await?;
    let io = IOTypeNotSend::new(TokioIo::new(stream));

    // For each connection, clone the counter to use in our service...
    let cnt = counter.clone();

    let service = service_fn(move |_| {
        let prev = cnt.get();
        cnt.set(prev + 1);
        let value = cnt.get();
        async move { Ok::<_, Error>(Response::new(Body::from(format!("Request #{}", value)))) }
    });

    tokio::task::spawn_local(async move {
        if let Err(err) = http2::Builder::new(LocalExec)
            .serve_connection(io, service)
            .await
        {
            let mut stdout = io::stdout();
            stdout
                .write_all(format!("Error serving connection: {:?}", err).as_bytes())
                .await
                .unwrap();
            stdout.flush().await.unwrap();
        }
    });
}

impl Iterator for Fields<'_> {
    type Item = (u8, Range<usize>);

    fn next(&mut self) -> Option<Self::Item> {
        // The fields in the response body are sequentially stored as [tag][string],
        // ending in a final, additional [nul]

        let ty = *self.storage.get(self.offset)?;

        if ty == 0 {
            return None;
        }

        // Consume the type byte
        self.offset = self.offset.checked_add(1)?;

        let start = self.offset;

        let len = memchr(b'\0', self.storage.get(start..)?)?;

        // Neither can overflow as they will always be `<= self.storage.len()`.
        let end = self.offset + len;
        self.offset = end + 1;

        Some((ty, start..end))
    }
}

