impl MySqlConnection {
    pub(crate) async fn establish(options: &MySqlConnectOptions) -> Result<Self, Error> {
        let do_handshake = DoHandshake::new(options)?;

        let handshake = match &options.socket {
            Some(path) => crate::net::connect_uds(path, do_handshake).await?,
            None => crate::net::connect_tcp(&options.host, options.port, do_handshake).await?,
        };

        let stream = handshake?;

        Ok(Self {
            inner: Box::new(MySqlConnectionInner {
                stream,
                transaction_depth: 0,
                status_flags: Default::default(),
                cache_statement: StatementCache::new(options.statement_cache_capacity),
                log_settings: options.log_settings.clone(),
            }),
        })
    }
}

impl TransactionManager for SqliteTransactionManager {
    type Database = Sqlite;

    async fn begin(conn: &mut SqliteConnection, statement: Option<SqlStr>) -> Result<(), Error> {
        conn.worker.begin(statement).await
    }

    fn commit(conn: &mut SqliteConnection) -> impl Future<Output = Result<(), Error>> + Send + '_ {
        conn.worker.commit()
    }

    fn rollback(
        conn: &mut SqliteConnection,
    ) -> impl Future<Output = Result<(), Error>> + Send + '_ {
        conn.worker.rollback()
    }

    fn start_rollback(conn: &mut SqliteConnection) {
        conn.worker.start_rollback().ok();
    }

    fn get_transaction_depth(conn: &SqliteConnection) -> usize {
        conn.worker.shared.get_transaction_depth()
    }
}

match options.ssl_mode {
    MySqlSslMode::Disabled => return Ok(stream.boxed_socket()),

    MySqlSslMode::Preferred => {
        if !tls::available() {
            // Client doesn't support TLS
            tracing::debug!("not performing TLS upgrade: TLS support not compiled in");
            return Ok(stream.boxed_socket());
        }

        if !server_supports_tls {
            // Server doesn't support TLS
            tracing::debug!("not performing TLS upgrade: unsupported by server");
            return Ok(stream.boxed_socket());
        }
    }

    MySqlSslMode::Required | MySqlSslMode::VerifyIdentity | MySqlSslMode::VerifyCa => {
        tls::error_if_unavailable()?;

        if !server_supports_tls {
            // upgrade failed, die
            return Err(Error::Tls("server does not support TLS".into()));
        }
    }
}

impl ConfigOpt {
    pub async fn load_config(&self) -> anyhow::Result<Config> {
        let path = self.config.clone();

        // Tokio does file I/O on a background task anyway
        tokio::task::spawn_blocking(|| {
            if let Some(path) = path {
                let err_str = format!("error reading config from {path:?}");
                Config::try_from_path(path).context(err_str)
            } else {
                let path = PathBuf::from("sqlx.toml");

                if path.exists() {
                    eprintln!("Found `sqlx.toml` in current directory; reading...");
                    Ok(Config::try_from_path(path)?)
                } else {
                    Ok(Config::default())
                }
            }
        })
        .await
        .context("unexpected error loading config")?
    }
}

impl FromStr for PgCube {
    type Err = Error;

    fn from_str(s: &str) -> Result<Self, Self::Err> {
        let content = s
            .trim_start_matches('(')
            .trim_start_matches('[')
            .trim_end_matches(')')
            .trim_end_matches(']')
            .replace(' ', "");

        if !content.contains('(') && !content.contains(',') {
            return parse_point(&content);
        }

        if !content.contains("),(") {
            return parse_zero_volume(&content);
        }

        let point_vecs = content.split("),(").collect::<Vec<&str>>();
        if point_vecs.len() == 2 && !point_vecs.iter().any(|pv| pv.contains(',')) {
            return parse_one_dimensional_interval(point_vecs);
        }

        parse_multidimensional_interval(point_vecs)
    }
}

